def which(program):
    """Find the absolute path of an executable without using 'which' command"""
    def is_executable(path):
        return os.path.isfile(path) and os.access(path, os.X_OK)

    # Check if the program contains a path component
    if os.path.dirname(program):
        if is_executable(program):
            return os.path.abspath(program)
        return None

    # Get PATH from environment or use default
    env_path = os.environ.get('PATH', os.defpath)
    for path_dir in env_path.split(os.pathsep):
        candidate = os.path.join(path_dir, program)
        if is_executable(candidate):
            return os.path.abspath(candidate)
    return None

