from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(resolve_entities=False, no_network=True)
    try:
        root = etree.fromstring(xml_data, parser)
    except etree.XMLSyntaxError:
        return None

    for student in root.findall('.//student'):
        user_elem = student.find('username')
        pass_elem = student.find('password')
        if user_elem is not None and pass_elem is not None:
            if user_elem.text == username and pass_elem.text == password:
                return {
                    'name': student.find('name').text,
                    'citizenship': student.find('citizenship').text,
                    'age': student.find('age').text
                }

    return None

