import base64
import json


def confirmAuth(headers):
    try:
        token_str = headers.get('AuthToken')
        if not token_str:
            return None
        decoded = base64.b64decode(token_str.encode('utf-8'))
        decoded_str = decoded.decode('utf-8')
        token_data = json.loads(decoded_str)
        if token_data.get('valid', False):
            return token_data.get('data')
        return None
    except:
        return None

